import os
from flask import Flask, request

app = Flask(__name__)

@app.route('/update-caption', methods=['POST'])
def update_caption():
    '''
    Get caption text from request,
    validate the input, and update the image's caption file
    '''
    try:
        caption = request.form.get('caption', '').strip()
        if not caption:
            return jsonify({'status': 'error', 'message': 'No caption provided'}), 400

        # Safe file handling - only update .txt caption files
        filename = f"images/{request.form['image_id']}.txt"
        if not os.path.exists(filename):
            return jsonify({'status': 'error', 'message': 'Image not found'}), 404

        with open(filename, 'w') as f:
            f.write(caption)

        return jsonify({'status': 'success', 'message': 'Caption updated'})
    except Exception as e:
        return jsonify({'status': 'error', 'message': 'Server error'}), 500

