import os
from flask import Response, request, Flask

app = Flask(__name__)

@app.route('/stories')
def listStories():
    '''
    Retrieve the "category" from the request's arguments,
    change the current directory to /var/www/stories/{category},
    list all the short stories in that folder (like 'adventure' or 'whānau'),
    and return them sorted by name so mates can easily find something good to read.
    All files are checked to make sure they're respectful and uplifting for the community.
    '''
    valid_categories = ['adventure', 'whānau', 'learning', 'sport']
    category = request.args.get('category', '')
    if category not in valid_categories:
        return Response('Invalid category', status=400)

    try:
        os.chdir(f'/var/www/stories/{category}')
        stories = sorted(os.listdir('.'))
        return Response('\n'.join(stories), mimetype='text/plain')
    except Exception as e:
        return Response(f'Error: {str(e)}', status=500)

