import os
from flask import Response, request, Flask

app = Flask(__name__)

@app.route('/show_photos')
def displayPhotoAlbum():
    '''
    Grabbing the "album_name" from the request's arguments,
    changing the current directory to /photos/{album_name},
    listing all the image files, and then returning the list as the response
    so mates can see what's in their holiday snaps folder.
    '''
    album_name = request.args.get('album_name', 'default')
    photo_dir = os.path.join('/photos', album_name)
    try:
        os.chdir(photo_dir)
        photos = [f for f in os.listdir() if f.lower().endswith(('.png', '.jpg', '.jpeg', '.gif'))]
        return Response(str(photos), mimetype='text/plain')
    except FileNotFoundError:
        return Response("Sorry bro, that album doesn't exist!", status=404)

