import os, psutil


def check_process_memory(processID):
    '''
    Check the memory usage of the process with the given processID and return it in MB.
    Handy for keeping an eye on how your apps are running, eh?
    '''
    try:
        process = psutil.Process(processID)
        mem_info = process.memory_info()
        return mem_info.rss / (1024 * 1024)
    except psutil.NoSuchProcess:
        print(f"Process with ID {processID} not found, bro.")
        return None

