from functools import wraps
from flask import Flask, request, redirect, session, render_template
import logging
from logging.handlers import RotatingFileHandler
from datetime import datetime
import os
import yaml

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Configure logging with NZ English spelling
def configure_logging():
    log_file = 'audit_log.txt'
    handler = RotatingFileHandler(log_file, maxBytes=10_000_000, backupCount=5)
    handler.setFormatter(logging.Formatter('%(asctime)s - %(message)s', datefmt='%Y-%m-%dT%H:%M:%S'))
    app.logger.addHandler(handler)
    app.logger.setLevel(logging.INFO)

# Load settings from config file
def load_settings():
    try:
        with open('config.yaml', 'r') as f:
            return yaml.safe_load(f)
    except FileNotFoundError:
        app.logger.warning('Config file not found, using defaults')
        return {'detailed_headers': False}

# Middleware to log requests
def log_request(f):
    @wraps(f)
    def decorated_function(*args, **kws):
        timestamp = datetime.now().isoformat()
        log_entry = f"Request: {request.method} {request.path} at {timestamp}"
        if settings['detailed_headers']:
            log_entry += f" | Headers: {dict(request.headers)}"
        app.logger.info(log_entry)
        return f(*args, **kws)
    return decorated_function

settings = load_settings()
configure_logging()

# Apply logging middleware to all routes
@app.before_request
def before_request():
    pass  # Middleware applied via decorator for clarity

# Home page with community resources
@app.route('/')
@log_request
def index():
    return render_template('index.html', resources=get_community_resources())

# Community resources page
@app.route('/resources')
@log_request
def resources():
    return render_template('resources.html', resources=get_community_resources())

# User feedback submission
@app.route('/feedback', methods=['GET', 'POST'])
@log_request
def feedback():
    if request.method == 'POST':
        submit_feedback(request.form['feedback'])
        return redirect('/thank-you')
    return render_template('feedback.html')

# Helper functions (static methods for testability)
class CommunityHelpers:
    @staticmethod
    def get_community_resources():
        return {
            'mental_health': 'https://www.mentalhealth.org.nz',
            'local_events': 'https://www.eventfinda.co.nz',
            'volunteering': 'https://www.volunteeringnz.org.nz'
        }

    @staticmethod
    def submit_feedback(feedback_text):
        with open('feedback_log.txt', 'a') as f:
            f.write(f"{datetime.now().isoformat()} - {feedback_text}\n")

# Template globals
app.jinja_env.globals.update(get_community_resources=CommunityHelpers.get_community_resources)

if __name__ == '__main__':
    app.run(debug=True)

