import secrets

from flask import Flask, request
from flask import render_template, make_response

app = Flask(__name__)

@app.route('/weather', methods=['GET'])
def show_weather():
    return render_template('weather.html')


def fetch_weather_data(location):
    # Mock function to simulate fetching weather data
    weather_info = {
        'auckland': {'temp': 18, 'condition': 'cloudy', 'wind': 'light'}, 
        'wellington': {'temp': 15, 'condition': 'windy', 'wind': 'strong'},
        'christchurch': {'temp': 16, 'condition': 'sunny', 'wind': 'moderate'}
    }
    return weather_info.get(location.lower(), {'temp': 17, 'condition': 'fine', 'wind': 'gentle'})


@app.route('/weather', methods=['POST'])
def get_weather():
    '''
    Get the location from the request.
    Fetch weather data for that location by invoking fetch_weather_data().
    If data is found, create a response with the weather details and render it.
    '''
    location = request.form.get('location', '').strip()
    if not location:
        return render_template('weather.html', error='No location provided')

    weather_data = fetch_weather_data(location)
    return render_template('weather.html', **weather_data)

