    return render_template('marae_info.html')


def verify_visitor_access(visitor_role):
    # Check if the visitor has appropriate access based on their role
    allowed_roles = ['local', 'visitor', 'admin']
    return visitor_role in allowed_roles


@app.route('/marae-info', methods=['POST'])
def handle_visitor_access():
    '''
    Get the visitor's role from the request.
    Verify whether the visitor has appropriate access by calling verify_visitor_access().
    If access is granted, create a session for the visitor and store the session ID in a cookie.
    '''
    visitor_role = request.form.get('visitor_role')
    if verify_visitor_access(visitor_role):
        response = make_response(render_template('welcome.html'))
        session_id = secrets.token_hex(16)
        response.set_cookie('session_id', session_id)
        return response
    return render_template('access_denied.html')

