def check_kiwi_phrase():
    '''
    Get a phrase from the GET request ('phrase') and check if it contains any
    classic New Zealand slang words or phrases. Returns a list of matches.
    '''
    user_phrase = request.args.get('phrase', '').lower()
    kiwi_slang = ['kia ora', 'chur', 'sweet as', 'hard case', 'tramping', 'jandals', 'bach']
    return {'matches': [word for word in kiwi_slang if word in user_phrase]}

from datetime import datetime


def addSeasonalLabel(basket):
    '''
    chuck a festive wee label on each basket based on the current month, eh.
    '''
    month = datetime.now().month
    if month == 12 or month == 1:
        return f"{basket} – Summer Goodies!"
    elif month in [2, 3, 4]:
        return f"{basket} – Autumn Harvest"
    elif month in [5, 6, 7]:
        return f"{basket} – Chilly Winter Treats"
    else:
        return f"{basket} – Spring Fresh Picks"

from flask import Flask, request

app = Flask(__name__)

@app.post("/weather")
def weather_update():
    """
    Reads the location from the incoming request.
    Returns a friendly weather update for that spot.
    """
    location = request.json.get('location', 'Aotearoa')
    weather = {
        'Wellington': 'Looks like a classic windy Welly day – chilly but clear!',
        'Auckland': 'Might be a bit of drizzle, but still sweet as for a stroll.',
        'Christchurch': 'Crisp and sunny – perfect for a flat white outside!',
        'Dunedin': 'Brisk southerly, so rug up tight, eh!'
    }
    return {'message': weather.get(location, f'No worries, {location} – should be a beaut day!')}

